package com.stockmind.application.factor;
import com.stockmind.application.financial.*;import com.stockmind.application.research.AnalystReport;import com.stockmind.application.sector.*;import com.stockmind.application.snapshot.*;import com.stockmind.domain.factor.*;import com.stockmind.domain.instrument.*;import com.stockmind.domain.market.*;import java.math.*;import java.time.*;import java.util.*;
public final class FactorCalculatorsAcceptanceTest{
 public static void main(String[]a){var wx=snapshot("SH603259","药明康德",new BigDecimal("20"),new BigDecimal("4"),financial("0.1584","1.0265","1000","300","200"),forecasts("8","9","10"));var quality=new QualityFactorCalculator().calculate(wx);require(quality.warnings().contains(FactorWarning.PROFIT_GROWTH_DIVERGES_FROM_REVENUE),"药明康德收入利润增速背离未触发");require(quality.warnings().contains(FactorWarning.CASH_CONVERSION_WEAK),"现金转化弱未触发");var wxGrowth=new GrowthFactorCalculator().calculate(wx);var wxRevenueGrowth=factor(wxGrowth,"latest_quarter_revenue_yoy_pct");require(wxRevenueGrowth.rawValue().compareTo(new BigDecimal("15.84"))==0&&wxRevenueGrowth.normalizedValue().compareTo(new BigDecimal("0.1584"))==0,"成长因子同比百分数与内部小数口径错误");var wl=snapshot("SZ000858","五粮液",new BigDecimal("14"),new BigDecimal("3"),financial("0.05","0.03","1000","300","100"),forecasts("7.32","6.30","5.07"));var growth=new GrowthFactorCalculator().calculate(wl);require(growth.signals().contains("forecast_growth_state=TURNING_NEGATIVE"),"五粮液下降EPS预测未识别");var mt=snapshot("SH600519","贵州茅台",new BigDecimal("20"),new BigDecimal("6"),financial("0.12","0.15","1000","500","600"),forecasts("70","78","85"));var valuation=new ValuationFactorCalculator().calculate(mt);var peer=valuation.factors().stream().filter(x->x.name().equals("peer_pe_premium_pct")).findFirst().orElseThrow();require(peer.quality()==FactorQuality.VALID&&peer.limitation().equals("pure_peer_sample_count=8"),"同行PE必须排除标的并保留纯同行样本数");Map<FactorCategory,FactorCategoryResult>all=new EnumMap<>(FactorCategory.class);for(FactorCalculator c:calculators())all.put(c.category(),c.calculate(mt));var scored=new FactorScoringService().score(all,FactorPolicy.of(InvestmentStyle.BALANCED));require(scored.categoryScores().size()==6,"六类分项评分缺失");require(scored.coverage().coveragePct().compareTo(BigDecimal.ZERO)>0,"覆盖率未计算");}
 static List<FactorCalculator>calculators(){return List.of(new ValuationFactorCalculator(),new QualityFactorCalculator(),new GrowthFactorCalculator(),new ExpectationRevisionFactorCalculator(),new MomentumRiskFactorCalculator(),new ShareholderReturnFactorCalculator());}
 private static PointInTimeStockSnapshot snapshot(String symbol,String name,BigDecimal pe,BigDecimal pb,FinancialSnapshot fs,List<AnalystReport>reports){LocalDate as=LocalDate.of(2026,7,20);Instrument inst=new Instrument(symbol,symbol.substring(2),Exchange.valueOf(symbol.substring(0,2)),InstrumentType.STOCK,name);MarketPriceSnapshot price=new MarketPriceSnapshot(symbol,name,as,as,PriceSourceType.REALTIME_QUOTE,new BigDecimal("100"),new BigDecimal("1000000"),new BigDecimal("50000000"),new BigDecimal("0.02"),new BigDecimal("1000000000"),new BigDecimal("800000000"),pe,pb,"tencent","q1",List.of());List<MarketBar>bars=bars(symbol,260);BarDataset ds=new BarDataset("b",bars,"tencent",Instant.parse("2026-07-20T08:00:00Z"),List.of());List<PeerMarketValue>peers=new ArrayList<>();peers.add(new PeerMarketValue(symbol,name,pe,pb,BigDecimal.TEN,"tencent"));for(int i=0;i<8;i++)peers.add(new PeerMarketValue("SH6000"+(10+i),"同行"+i,BigDecimal.valueOf(18+i),BigDecimal.valueOf(3+i*.1),BigDecimal.TEN,"tencent"));IndustryPeerSnapshot ips=new IndustryPeerSnapshot(as,true,true,new SectorConstituentSet("BK","行业",List.of()),peers,List.of());return new PointInTimeStockSnapshot("r",inst,as,price,ds,ds,ips,com.stockmind.application.risk.SupplementalRiskSnapshot.unavailable(as,"fixture"),fs,reports,List.of(new com.stockmind.application.dividend.DividendDistribution(as.minusMonths(2),new BigDecimal("20"),"实施")),0,0,Map.of());}
 private static FinancialSnapshot financial(String revYoy,String profitYoy,String revenue,String profit,String ocf){LocalDate rp=LocalDate.of(2026,3,31),pub=LocalDate.of(2026,4,30);Map<String,CanonicalFinancialValue>iv=Map.of("营业收入",cv("营业收入",revenue,FinancialValueUnit.CNY),"净利润",cv("净利润",profit,FinancialValueUnit.CNY));Map<String,CanonicalFinancialValue>iy=Map.of("营业收入",cv("营业收入",revYoy,FinancialValueUnit.RATIO),"净利润",cv("净利润",profitYoy,FinancialValueUnit.RATIO));var income=new CanonicalFinancialStatementPeriod(rp,pub,pub,StatementScope.CUMULATIVE_QUARTER,false,"lrb",iv,iy);var balance=new CanonicalFinancialStatementPeriod(rp,pub,pub,StatementScope.CUMULATIVE_QUARTER,false,"fzb",Map.of("资产总计",cv("资产总计","2000",FinancialValueUnit.CNY),"负债合计",cv("负债合计","600",FinancialValueUnit.CNY)),Map.of());var cash=new CanonicalFinancialStatementPeriod(rp,pub,pub,StatementScope.CUMULATIVE_QUARTER,false,"llb",Map.of("经营活动产生的现金流量净额",cv("经营活动产生的现金流量净额",ocf,FinancialValueUnit.CNY)),Map.of());return new FinancialSnapshot(Map.of("lrb",List.of(income),"fzb",List.of(balance),"llb",List.of(cash)),0);}
 private static FactorValue factor(FactorCategoryResult r,String n){return r.factors().stream().filter(x->x.name().equals(n)).findFirst().orElseThrow();}private static CanonicalFinancialValue cv(String n,String v,FinancialValueUnit u){return new CanonicalFinancialValue(n,v,new BigDecimal(v),u,u.name());}private static List<AnalystReport>forecasts(String a,String b,String c){List<AnalystReport>r=new ArrayList<>();for(int i=0;i<3;i++)r.add(new AnalystReport("r"+i,"","研报","机构"+i,LocalDate.of(2026,7,1),"买入",new BigDecimal(a),new BigDecimal(b),new BigDecimal(c),""));return r;}private static List<MarketBar>bars(String symbol,int n){List<MarketBar>r=new ArrayList<>();LocalDate start=LocalDate.of(2025,7,1);for(int i=0;i<n;i++){Instant t=start.plusDays(i).atTime(15,0).atZone(ZoneId.of("Asia/Shanghai")).toInstant();BigDecimal p=BigDecimal.valueOf(80+i*.1);r.add(new MarketBar(symbol,BarInterval.DAY_1,t.minusSeconds(19800),t,p,p,p,p,BigDecimal.valueOf(1000+i),BigDecimal.valueOf(100000+i),AdjustmentMode.FORWARD));}return r;}private static void require(boolean c,String m){if(!c)throw new AssertionError(m);}
}
